const trigger = $('New Lead Added').first().json;
const company = (trigger.Company || '').trim();
const cutoff = Date.now() - (30 * 24 * 60 * 60 * 1000);

let isRecent = false;
const rows = $input.all();

if (rows && rows.length > 0 && rows[0].json && rows[0].json.Company) {
  isRecent = rows.some(row => {
    const rowCompany = (row.json.Company || '').trim();
    if (rowCompany.toLowerCase() !== company.toLowerCase()) return false;
    if (!row.json.Recency) return false;
    return new Date(row.json.Recency).getTime() > cutoff;
  });
}

return [{
  json: {
    isRecent,
    company,
    website: trigger.Website || '',
    contactName: trigger['Contact Name'] || '',
    role: trigger.Role || '',
    email: trigger.Email || ''
  }
}];

